// LPRecipePanel.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};
LOGICPULSE.UI = LOGICPULSE.UI || {};


//=============================================================================
// Recipe Panel
//=============================================================================

LOGICPULSE.UI.RecipePanel = class extends LOGICPULSE.UI.Element {


    //--------------------------------
    // Initialize
    //--------------------------------

    constructor() {

        super();

        this._recipe = [];

        this._slots = [];

        this.create();

    }



    //--------------------------------
    // Create
    //--------------------------------

    create() {

        this.createBackground();

        this.createSlots();

    }



    //--------------------------------
    // Background Boxes
    //--------------------------------

    createBackground() {

        const layout =
            LOGICPULSE.Layout.Synthesizer.RecipeItemBoxes;


        for (let i = 0; i < 4; i++) {

            const sprite =
                this.createSprite(

                    LOGICPULSE.Assets.Folders.Synthesizer,

                    LOGICPULSE.Assets.Images.Synthesizer.RecipeItemBoxes

                );


            sprite.x =
                layout.firstSlot.x +
                (i * layout.spacing);


            sprite.y =
                layout.firstSlot.y;


        }

    }



    //--------------------------------
    // Create Slots
    //--------------------------------

    createSlots() {

        const layout =
            LOGICPULSE.Layout.Synthesizer.RecipeItemBoxes;

        for (let i = 0; i < 4; i++) {

            const slot = new PIXI.Container();

            slot.x =
                layout.firstSlot.x +
                (i * layout.spacing);

            slot.y =
                layout.firstSlot.y;

            this.addChild(slot);

            this._slots.push(slot);

        }

    }



    //--------------------------------
    // Set Recipe
    //--------------------------------

    setRecipe(recipe) {

        this._recipe = recipe || [];

        this.refresh();

    }



    //--------------------------------
    // Refresh
    //--------------------------------

    refresh() {


        for (let i = 0; i < this._slots.length; i++) {


            const slot =
                this._slots[i];


            this.clearSlot(slot);


            const ingredient =
                this._recipe[i];


            if (!ingredient) {

                continue;

            }


            this.drawMaterial(

                slot,

                ingredient

            );

        }

    }



    //--------------------------------
    // Clear Slot
    //--------------------------------

    clearSlot(slot) {


        while (slot.children.length > 0) {

            slot.removeChildAt(0);

        }

    }



//--------------------------------
// Draw Material
//--------------------------------

    drawMaterial(slot, ingredient) {

        const item = $dataItems[ingredient.itemId];

        if (!item) {

            return;

        }

        //--------------------------------
        // Icon
        //--------------------------------

        const icon = LOGICPULSE.Assets.createItemSprite(item);

        slot.addChild(icon);

        //--------------------------------
        // Amount
        //--------------------------------

        const amountLayout =
            LOGICPULSE.Layout.Synthesizer.RecipeItemBoxes.Amount;

        const amount = this.createText({

            text: String(ingredient.amount),

            x: amountLayout.x,
            y: amountLayout.y,

            width: amountLayout.width,
            height: amountLayout.height,

            align: amountLayout.align,

            fontSize: amountLayout.fontSize

        });

        slot.addChild(amount);

        //--------------------------------
        // Name
        //--------------------------------

        const nameLayout =
            LOGICPULSE.Layout.Synthesizer.RecipeItemBoxes.ItemName;

        let name = item.name;

        // Optional: shorten long names
        if (name.length > 16) {

            name = name.substring(0, 9) + "...";

        }

        const nameText = this.createText({

            text: name,

            x: nameLayout.x,
            y: nameLayout.y,

            width: nameLayout.width,
            height: nameLayout.height,

            align: nameLayout.align,

            fontSize: nameLayout.fontSize

        });

        slot.addChild(nameText);

    }



    //--------------------------------
    // Selected Item
    //--------------------------------

    setItem(item) {


        if (!item) {

            this.clear();

            return;

        }


        this.setRecipe(

            LOGICPULSE.RecipeManager.recipe(item)

        );

    }



    //--------------------------------
    // Clear
    //--------------------------------

    clear() {

        this.setRecipe([]);

    }


};


//=============================================================================
// LPQuantityController.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};
LOGICPULSE.UI = LOGICPULSE.UI || {};


//=============================================================================
// Quantity Controller
//=============================================================================

LOGICPULSE.UI.QuantityController = class extends LOGICPULSE.UI.Element {


    //--------------------------------
    // Initialize
    //--------------------------------

    constructor() {

        super();

        this._item = null;

        this._value = 1;

        this._max = 1;

        this._arrowTimer = 0;

        this.create();

    }



    //--------------------------------
    // Create
    //--------------------------------

    create() {

        this.createBackground();

        this.createArrows();

        this.createNumber();

        this.createMaxNumber();

        this.refresh();

    }



    //--------------------------------
    // Background
    //--------------------------------

    createBackground() {

        const layout =

            LOGICPULSE.Layout.Synthesizer.Showcase.NumberControls;


        this._background = this.createSprite(

            LOGICPULSE.Assets.Folders.Synthesizer,

            LOGICPULSE.Assets.Images.Synthesizer.ItemNumberController,

            layout.x,

            layout.y

        );

    }



    //--------------------------------
    // Arrows
    //--------------------------------

    createArrows() {

        const layout =

            LOGICPULSE.Layout.Synthesizer.Showcase.NumberControls.Arrows;


        this._leftArrow = this.createSprite(

            LOGICPULSE.Assets.Folders.Synthesizer,

            LOGICPULSE.Assets.Images.Synthesizer.ItemDecrease,

            layout.x,

            layout.y

        );


        this._rightArrow = this.createSprite(

            LOGICPULSE.Assets.Folders.Synthesizer,

            LOGICPULSE.Assets.Images.Synthesizer.ItemIncrease,

            layout.x + layout.spacing,

            layout.y

        );


        this._leftArrow.visible = false;

        this._rightArrow.visible = false;

    }



    //--------------------------------
    // Number
    //--------------------------------

    createNumber() {

        const layout =

            LOGICPULSE.Layout.Synthesizer.Showcase.NumberControls.CurrentNumber;


        this._numberText = this.createText({

            text: "1",

            x: layout.x,

            y: layout.y,

            width: layout.width,

            height: layout.height,

            align: layout.align,

            fontSize: layout.fontSize

        });

    }

    //--------------------------------
    // Max Number
    //--------------------------------

    createMaxNumber() {

        const layout =

            LOGICPULSE.Layout.Synthesizer.Showcase.NumberControls.MaxNumber;

        this._maxNumberText = this.createText({

            text: "1",

            x: layout.x,

            y: layout.y,

            width: layout.width,

            height: layout.height,

            align: layout.align,

            fontSize: layout.fontSize

        });

    }


    //--------------------------------
    // Set Item
    //--------------------------------

    setItem(item) {

        this._item = item;

        this._value = 1;


        if (!item) {

            this._max = 1;

        }

        else {

            this._max = LOGICPULSE.RecipeManager.maxCraftAmount(

                item

            );

            this._value = this._max > 0 ? 1 : 0;

        }


        this.refresh();

    }



    //--------------------------------
    // Increase
    //--------------------------------

    increase(amount = 1) {

        const old = this._value;


        if (this._max <= 0) {

            return;

        }

        this._value = Math.min(

            this._value + amount,

            this._max

        );


        if (this._value !== old) {

            this.showArrow("right");

            this.refresh();

        }

    }



    //--------------------------------
    // Decrease
    //--------------------------------

    decrease(amount = 1) {

        const old = this._value;


        if (this._max <= 0) {

            return;

        }

        this._value = Math.max(

            this._value - amount,

            1

        );


        if (this._value !== old) {

            this.showArrow("left");

            this.refresh();

        }

    }



    //--------------------------------
    // Set Value
    //--------------------------------

    setValue(value) {

        if (this._max <= 0) {

            this._value = 0;

        }

        else {

            this._value = Math.max(

                1,

                Math.min(

                    value,

                    this._max

                )

            );

        }


        this.refresh();

    }



    //--------------------------------
    // Show Arrow
    //--------------------------------

    showArrow(direction) {

        this._arrowTimer = 20;


        this._leftArrow.visible =

            direction === "left";


        this._rightArrow.visible =

            direction === "right";

    }



    //--------------------------------
    // Refresh
    //--------------------------------

    refresh() {

        if (this._max <= 0) {

            this._numberText.setText("0/0");

            this._maxNumberText.setText("0");

        }

        else {

            this._numberText.setText(

                `${this._value}/${this._max}`

            );

            this._maxNumberText.setText(

                String(this._max)

            );

        }

    }


    //--------------------------------
    // Update
    //--------------------------------

    update() {

        if (this._arrowTimer > 0) {

            this._arrowTimer--;

            if (this._arrowTimer <= 0) {

                this._leftArrow.visible = false;

                this._rightArrow.visible = false;

            }

        }

    }



    //--------------------------------
    // Value
    //--------------------------------

    value() {

        return this._value;

    }



    //--------------------------------
    // Max
    //--------------------------------

    max() {

        return this._max;

    }


};


