//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};

LOGICPULSE.Assets.initialize();


(() => {

    const pluginName = LOGICPULSE.Version.plugin;

    PluginManager.registerCommand(

        pluginName,
        "OpenInventory",
        () => {

            SceneManager.push(LOGICPULSE.Scenes.Inventory);

        }

    );

})();

